  function gen_correction_prompt(issues){var base=gen_cinematic_prompt();var fixes=issues.map(function(issue){var map={'Too many people':'Reduce number of people to match scene count exactly','Missing character':'Restore the missing character as described in the character lock','Wrong ethnicity':'Restore correct ethnicity as defined in character lock','Wrong body type':'Restore correct body type as defined in character lock','Wrong wardrobe':'Restore ancient Hebrew clothing, remove any modern elements','Face changed':'Restore the character face to match the approved canonical reference','Image cropped':'Reframe so all characters are fully visible, no cropping','Scene unrelated':'Refocus scene on described location and characters','Too modern':'Remove all modern objects, buildings, and styling','Not enough diversity':'Ensure diverse ancient population as required by world rules','Wrong family count':'Use exact approved family member count for this scene type'};return map[issue]||issue;});return 'CORRECTION: '+fixes.join('. ')+'. Base scene: '+base;}
